INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Shadow Touched', 'General Feat', 'Level 4+', 'Your exposure to the Shadowfell''s magic grants you the following benefits.', '[{"name":"Ability Score Increase","description":"Increase your Intelligence, Wisdom, or Charisma score by 1, to a maximum of 20."},{"name":"Shadow Magic","description":"Choose one level 1 spell from the Illusion or Necromancy school of magic. You always have that spell and the Invisibility spell prepared. You can cast each of these spells without expending a spell slot. Once you cast either spell in this way, you can''t cast that spell in this way again until you finish a Long Rest. You can also cast these spells using spell slots you have of the appropriate level. The spells’ spellcasting ability is the ability increased by this feat."}]'::jsonb, FALSE, ARRAY['common', 'generalfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
