INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Genie Magic', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+)
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Harper Teamwork', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+, Harper Agent Feat)', '[{"name":"Ability Score Increase","description":"Increase your Dexterity or Charisma score by 1, to a maximum of 20."},{"name":"Withering Wordplay","description":"When you take the Help action to assist an ally’s attack roll against an enemy, that enemy also has Disadvantage on the first saving throw it makes before the start of your next turn."},{"name":"Inspiring Willpower","description":"If you succeed on a saving throw to end the Frightened or Paralyzed condition on yourself, you can choose one ally you can see within 30 feet of yourself that has the same condition. That condition immediately ends for that ally."}]'::jsonb, FALSE, ARRAY['faerun', 'frhof', 'generalfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Lordly Resolve', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+, Lords’ Alliance Agent Feat)
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Mythal Touched', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+)
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Order''s Resilience', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+, Tyro of the Gauntlet Feat)', '[{"name":"Ability Score Increase","description":"Increase your Strength, Wisdom, or Charisma score by 1, to a maximum of 20."},{"name":"Resurge","description":"When you have the Prone condition, you can right yourself with only 5 feet of movement."},{"name":"Stronger Together","description":"If you are within 5 feet of an ally that doesn’t have the Incapacitated condition, you and that ally have Advantage on Strength saving throws. You can’t use this benefit while you have the Incapacitated condition."}]'::jsonb, FALSE, ARRAY['faerun', 'frhof', 'generalfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Purple Dragon Commandant', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+, Purple Dragon Rook Feat or Martial Weapon Proficiency)', '[{"name":"Ability Score Increase","description":"Increase your Strength or Dexterity score by 1, to a maximum of 20."},{"name":"Encourage Ally","description":"As a Bonus Action, you bolster one ally you can see within 30 feet. The ally gains Temporary Hit Points equal to 2d6 plus the modifier of the ability score increased by this feat. You can take this Bonus Action a number of times equal to your Proficiency Bonus, and you regain all uses when you finish a Long Rest."},{"name":"Last Stand","description":"You have Advantage on attack rolls while Bloodied."}]'::jsonb, FALSE, ARRAY['faerun', 'frhof', 'generalfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Zhentarim Tactics', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+, Zhentarim Ruffian Feat)', '[{"name":"Ability Score Increase","description":"Increase your Dexterity or Charisma score by 1, to a maximum of 20."},{"name":"Retaliate","description":"Immediately after a creature within 5 feet of you hits you with a melee attack, you can make an Opportunity Attack against that creature."},{"name":"Versatile Merc","description":"When you finish a Long Rest, choose a skill in which you have proficiency. You have Expertise in that skill until you finish your next Long Rest."}]'::jsonb, FALSE, ARRAY['faerun', 'frhof', 'generalfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Spellfire Adept', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+, Spellfire Spark Feat or the Spellcasting or Pact Magic Feature)', '[{"name":"Ability Score Increase","description":"Increase your Intelligence, Wisdom, or Charisma score by 1, to a maximum of 20."},{"name":"Fueled Spellfire","description":"Once per turn, when a spell you cast deals Radiant damage, you can expend up to two Hit Point Dice, roll them, and add the total rolled to one damage roll of the spell."},{"name":"Searing Spellfire","description":"When you make a damage roll that deals Radiant damage, it ignores Resistance to Radiant damage."}]'::jsonb, FALSE, ARRAY['faerun', 'frhof', 'generalfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Street Justice', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+)', '[{"name":"Ability Score Increase","description":"Increase your Strength or Dexterity score by 1, to a maximum of 20."},{"name":"Headlock","description":"Your allies have Advantage on attack rolls against a creature Grappled by you."},{"name":"Sturdy Knot","description":"When you use Chain, Manacles, or Rope to bind a creature, add your Proficiency Bonus to the DC to escape or burst the Chain, Manacles, or Rope."},{"name":"Tough Talk","description":"A creature’s Hostile attitude doesn’t impose Disadvantage on your Charisma (Intimidation) checks to influence that creature."}]'::jsonb, FALSE, ARRAY['faerun', 'frhof', 'generalfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Bloodlust', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+)
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Bomber', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+)', '[{"name":"Ability Score Increase","description":"Increase your Dexterity score by 1, to a maximum of 20."},{"name":"Far Lobber","description":"When you use the Attack action to throw a vial or flask, you can target an object or creature you can see within 40 feet of yourself."},{"name":"Long Shots","description":"Attacking at long range doesn’t impose Disadvantage on your attack rolls with Thrown weapons."}]'::jsonb, FALSE, ARRAY['aboh', 'exotic', 'generalfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Cloying Mists', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+)', '[{"name":"Ability Score Increase","description":"Increase your Intelligence, Wisdom, or Charisma score by 1, to a maximum of 20."},{"name":"Arise, Fog","description":"You always have the Fog Cloud spell prepared. You can cast it without a spell slot, and you must finish a Long Rest before you can cast it in this way again. You can also cast it using spell slots you have of the appropriate level. Your spellcasting ability for the spell is the ability increased by this feat."},{"name":"Grasping Mist","description":"Whenever you cast Fog Cloud, nonmagical flames in the spell’s Sphere are extinguished, and creatures other than you and your allies have their Speed reduced by 5 feet while in the spell’s Sphere."}]'::jsonb, FALSE, ARRAY['aboh', 'exotic', 'generalfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Delicious Pain', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 20."},{"name":"Toughened Flesh","description":"Immediately after you take Bludgeoning, Piercing, or Slashing damage, you can take a Reaction to gain Resistance to Bludgeoning, Piercing, and Slashing damage until the start of your next turn. Once you use this benefit, you can’t use it again until you finish a Short or Long Rest."}]'::jsonb, FALSE, ARRAY['aboh', 'exotic', 'generalfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Light Bringer', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+)', '[{"name":"Ability Score Increase","description":"Increase your Intelligence, Wisdom, or Charisma score by 1, to a maximum of 20."},{"name":"Sacred Magic","description":"You learn the Light spell and can cast it without Material components. If you already know that cantrip, you learn a different Cleric cantrip of your choice. The spell’s spellcasting ability is the ability increased by this feat."},{"name":"Solar Luminance","description":"When you cast Light, you can have the light from the spell be sunlight. Once you use this benefit, you can’t use it again until you finish a Long Rest."},{"name":"Sun’s Healing","description":"As a Bonus Action while within sunlight, you can expend one of your Hit Point Dice, roll the die, and regain a number of Hit Points equal to the roll. Once you use this benefit, you can’t use it again until you finish a Short or Long Rest."}]'::jsonb, FALSE, ARRAY['aboh', 'exotic', 'generalfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Love Bites', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 20."},{"name":"Endearing Pain","description":"Immediately after you damage a creature with a Melee weapon or an Unarmed Strike, you can take a Bonus Action to give the target the Charmed condition until the start of your next turn or until you or your allies damage it. Once you use this benefit, you can’t use it again until you finish a Short or Long Rest."}]'::jsonb, FALSE, ARRAY['aboh', 'exotic', 'generalfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Putrefy', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 20."},{"name":"Necrosis","description":"When you make a damage roll that deals Necrotic damage, you can cause one creature taking that damage to have the Poisoned condition until the start of your next turn. Once you use this benefit, you can’t use it again until you finish a Short or Long Rest."}]'::jsonb, FALSE, ARRAY['aboh', 'exotic', 'generalfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Rebuke', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 20."},{"name":"Radiant Strike","description":"When you make a damage roll that deals Radiant damage, you can cause one Huge or smaller creature taking the damage to have the Prone condition. Once you use this benefit, you can’t use it again until you finish a Short or Long Rest."}]'::jsonb, FALSE, ARRAY['aboh', 'exotic', 'generalfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Vampire Touched', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+)', '[{"name":"Ability Score Increase","description":"Increase your Intelligence, Wisdom, or Charisma score by 1, to a maximum of 20."},{"name":"Vampire Magic","description":"Choose one level 1 spell from the Enchantment or Illusion school of magic. You always have that spell and the Spider Climb spell prepared. You can cast each of these spells without expending a spell slot, but when you cast Spider Climb this way, you must target yourself, and you must finish a Long Rest before you can cast each spell in this way again. You can also cast either spell using spell slots you have of the appropriate level. Your spellcasting ability for the spells is the ability increased by this feat."}]'::jsonb, FALSE, ARRAY['aboh', 'exotic', 'generalfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Archery', 'General Feat', 'Fighting Style Feature', 'You gain a +2 bonus to attack rolls you make with Ranged weapons.', '[]'::jsonb, FALSE, ARRAY['fightingstylefeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Blind Fighting', 'General Feat', 'Fighting Style Feature', 'You have Blindsight with a range of 10 feet.', '[]'::jsonb, FALSE, ARRAY['fightingstylefeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Defense', 'General Feat', 'Fighting Style Feature', 'While you''re wearing Light, Medium, or Heavy armor, you gain a +1 bonus to Armor Class.', '[]'::jsonb, FALSE, ARRAY['fightingstylefeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Dueling', 'General Feat', 'Fighting Style Feature', 'When you''re holding a Melee weapon in one hand and no other weapons, you gain a +2 bonus to damage rolls with that weapon.', '[]'::jsonb, FALSE, ARRAY['fightingstylefeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Interception', 'General Feat', 'Fighting Style Feature', 'When a creature you can see hits another creature within 5 feet of you with an attack roll, you can take a Reaction to reduce the damage dealt to the target by 1d10 plus your Proficiency Bonus. You must be holding a Shield or a Simple or Martial weapon to use this Reaction.', '[]'::jsonb, FALSE, ARRAY['fightingstylefeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Great Weapon Fighting', 'General Feat', 'Fighting Style Feature', 'When you roll damage for an attack you make with a Melee weapon that you are holding with two hands, you can treat any 1 or 2 on a damage die as a 3. The weapon must have the Two-Handed or Versatile property to gain this benefit.', '[]'::jsonb, FALSE, ARRAY['fightingstylefeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Protection', 'General Feat', 'Fighting Style Feature', 'When a creature you can see attacks a target other than you that is within 5 feet of you, you can take a Reaction to interpose your Shield if you''re holding one. You impose Disadvantage on the triggering attack roll and all other attack rolls against the target until the start of your next turn if you remain within 5 feet of the target.', '[]'::jsonb, FALSE, ARRAY['fightingstylefeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Thrown Weapon Fighting', 'General Feat', 'Fighting Style Feature', 'When you hit with a ranged attack roll using a weapon that has the Thrown property, you gain a +2 bonus to the damage roll.', '[]'::jsonb, FALSE, ARRAY['fightingstylefeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Unarmed Fighting', 'General Feat', 'Fighting Style Feature', 'When you hit with your Unarmed Strike and deal damage, you can deal Bludgeoning damage equal to 1d6 plus your Strength modifier instead of the normal damage of an Unarmed Strike. If you aren''t holding any weapons or a Shield when you make the attack roll, the d6 becomes a d8.
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Two Weapon Fighting', 'General Feat', 'Fighting Style Feature', 'When you make an extra attack as a result of using a weapon that has the Light property, you can add your ability modifier to the damage of that attack if you aren''t already adding it to the damage.', '[]'::jsonb, FALSE, ARRAY['fightingstylefeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
