INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Boon of Bloodshed', 'General Feat', NULL, 'Epic Boon Feat (Prerequisite: Level 19+)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 30."},{"name":"Killer’s Fortune","description":"When an enemy you can see is reduced to 0 Hit Points, you gain Advantage on the next attack roll you make before the end of your next turn."},{"name":"Power from Pain","description":"Once per turn, when you make an attack roll while Bloodied, you can deal extra damage to the target equal to your Proficiency Bonus. The extra damage’s type is the same as the attack’s type."}]'::jsonb, FALSE, ARRAY['epicboonfeat', 'faerun', 'frhof']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Boon of Siberys', 'General Feat', NULL, 'Epic Boon Feat (Prerequisite: Level 19+, Eberron Campaign)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 30."},{"name":"Aberrant Magic","description":"Choose a level 8 or lower spell from the Sorcerer spell list or a spell from the Siberys Dragonmark Spells table (the table includes dragonmark suggestions if you’d like to associate a spell with one of the marks). You always have that spell prepared. You can cast it once without a spell slot or spell components, and you regain the ability to cast it in that way when you finish a Short or Long Rest. You can also cast this spell using any spell slots you have of the appropriate level. Intelligence, Wisdom, or Charisma is your spellcasting ability for this spell (choose when you gain this feat)."},{"name":"Siberys Dragonmark Spells","description":""}]'::jsonb, FALSE, ARRAY['eberron', 'efota', 'epicboonfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Boon of Bountiful Health', 'General Feat', NULL, 'Epic Boon Feat (Prerequisite: Level 19+)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 30."},{"name":"Augmented Health","description":"When you gain Temporary Hit Points, increase the number of Temporary Hit Points you gain by 5."},{"name":"Superior Recuperation","description":"When you spend one or more Hit Point Dice to regain Hit Points, you can instead use the highest number possible for each die."}]'::jsonb, FALSE, ARRAY['epicboonfeat', 'faerun', 'frhof']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Boon of Communication', 'General Feat', NULL, 'Epic Boon Feat (Prerequisite: Level 19+)', '[{"name":"Ability Score Increase","description":"Increase your Intelligence, Wisdom, or Charisma score by 1, to a maximum of 30."},{"name":"Cunning Speaker","description":"You don’t have Disadvantage on ability checks to influence Hostile creatures."},{"name":"Gifted Interpreter","description":"You understand the literal meaning of any language you hear or see signed, and you can understand the literal meaning of any written language you see."},{"name":"Mental Communication","description":"You gain telepathy with a range of 120 feet."}]'::jsonb, FALSE, ARRAY['epicboonfeat', 'faerun', 'frhof']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Boon of Desperate Resilience', 'General Feat', NULL, 'Epic Boon Feat (Prerequisite: Level 19+)', '[{"name":"Ability Score Increase","description":"Increase your Strength or Constitution score by 1, to a maximum of 30."},{"name":"Defense of Body and Mind","description":"While you are Bloodied, you have Resistance to every damage type except Force."}]'::jsonb, FALSE, ARRAY['epicboonfeat', 'faerun', 'frhof']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Boon of Exquisite Radiance', 'General Feat', NULL, 'Epic Boon Feat (Prerequisite: Level 19+)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 30."},{"name":"Eternal Rest","description":"Creatures you reduce to 0 Hit Points can’t become Undead."},{"name":"Powerful Radiance","description":"When you make a damage roll that deals Radiant damage, you can instead use the highest number possible for each damage die. Once you use this benefit, you can’t do so again until you finish a Long Rest."}]'::jsonb, FALSE, ARRAY['epicboonfeat', 'faerun', 'frhof']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Boon of Fluid Forms', 'General Feat', NULL, 'Epic Boon Feat (Prerequisite: Level 19+)
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Boon of Revelry', 'General Feat', NULL, 'Epic Boon Feat (Prerequisite: Level 19+)
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Boon of Fortune''s Favor', 'General Feat', NULL, 'Epic Boon Feat (Prerequisite: Level 19+)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 30."},{"name":"Saving Throw Reroll","description":"When you fail a saving throw, you can reroll it and must use the new roll. Once you use this benefit, you can’t do so again until the start of your next turn."}]'::jsonb, FALSE, ARRAY['epicboonfeat', 'faerun', 'frhof']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Boon of Poison Mastery', 'General Feat', NULL, 'Epic Boon Feat (Prerequisite: Level 19+)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 30."},{"name":"Antitoxic","description":"You have Immunity to Poison damage and the Poisoned condition."},{"name":"Perfect Poisoner","description":"Once per turn, when you roll dice to determine Poison damage a creature takes from your attack, spell, or feature, you can instead use the highest number possible for each die."}]'::jsonb, FALSE, ARRAY['epicboonfeat', 'faerun', 'frhof']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Boon of Terror', 'General Feat', NULL, 'Epic Boon Feat (Prerequisite: Level 19+)', '[{"name":"Ability Score Increase","description":"Increase your Charisma score by 1, to a maximum of 30."},{"name":"Fearless","description":"You have Immunity to the Frightened condition."},{"name":"Flee, Fools!","description":"When a creature with the Frightened condition starts its turn within 60 feet of you, you can take a Reaction to stoke its terror, provided you can see the creature and it isn’t behind Total Cover. If you do so, the creature must succeed on a Wisdom saving throw (DC 8 plus your Charisma modifier and your Proficiency Bonus) or spend its turn moving away from you by the fastest available means. Once you use this benefit, you can’t use it again until you finish a Short or Long Rest."},{"name":"Intimidating","description":"You gain Proficiency in the Intimidation skill if you don’t already have it. You also gain Expertise in Intimidation."}]'::jsonb, FALSE, ARRAY['epicboonfeat', 'faerun', 'frhof']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Boon of the Soul Drinker', 'General Feat', NULL, 'Epic Boon Feat (Prerequisite: Level 19+)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 30."},{"name":"Grave Resistance","description":"You have Resistance to Cold damage and Necrotic damage."},{"name":"Siphon Life","description":"When an enemy within 120 feet of you is reduced to 0 Hit Points, you can take a Reaction to regain 50 Hit Points. Once you use this benefit, you can’t use it again until you finish a Short or Long Rest."}]'::jsonb, FALSE, ARRAY['epicboonfeat', 'faerun', 'frhof']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Boon of the Furious Storm', 'General Feat', NULL, 'Epic Boon Feat (Prerequisite: Level 19+, Spellcasting or Pact Magic Feature)', '[{"name":"Ability Score Increase","description":"Increase your Intelligence, Wisdom, or Charisma score by 1, to a maximum of 30."},{"name":"Eye of the Storm","description":"You have Resistance to Lightning and Thunder damage. While you are Bloodied, you have Immunity to Lightning and Thunder damage."},{"name":"Storm’s Strength","description":"Creatures have Disadvantage on saving throws against your spells that deal Lightning or Thunder damage."}]'::jsonb, FALSE, ARRAY['epicboonfeat', 'faerun', 'frhof']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Boon of the Bright Sun', 'General Feat', NULL, 'Epic Boon Feat (Prerequisite: Level 19+)', '[{"name":"Ability Score Increase","description":"Increase your Constitution, Wisdom, or Charisma score by 1, to a maximum of 30."},{"name":"Daylight Presence","description":"As a Bonus Action, you radiate a 30-foot Emanation of Bright Light that is sunlight. If any of the Emanation’s area overlaps with an area of Darkness created by a spell, that spell is dispelled. The Emanation lasts until you dismiss it (no action required), die, or have the Incapacitated condition."},{"name":"Fortifying Light","description":"When your Daylight Presence is active, at the start of each of your turns, you and allies you can see in your Daylight Presence gain 10 Temporary Hit Points."}]'::jsonb, FALSE, ARRAY['epicboonfeat', 'faerun', 'frhof']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Boon of Blazing Dawn', 'General Feat', NULL, 'Epic Boon Feat (Prerequisite: Level 19+)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 30."},{"name":"Beloved of the Sun","description":"You have Immunity to Radiant damage."},{"name":"Blazing Strike","description":"When you hit a creature with a weapon attack, the damage can be Radiant or the weapon’s normal damage type (your choice)."},{"name":"Burst of Sunlight","description":"Once per turn when you hit a creature with an attack that deals Radiant damage, you can emit Bright Light in a 30-foot radius from yourself and Dim Light for an additional 30 feet until the start of your next turn. This light is sunlight."}]'::jsonb, FALSE, ARRAY['aboh', 'epicboonfeat', 'exotic']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Boon of Looming Shadows', 'General Feat', NULL, 'Epic Boon Feat (Prerequisite: Level 19+)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 30."},{"name":"Shadowy Stretch","description":"When you take the Attack action, your reach for your Melee weapon attacks increases by 10 feet until the end of your turn."},{"name":"Dancing Silhouette","description":"You can take the Dodge action as a Bonus Action."}]'::jsonb, FALSE, ARRAY['aboh', 'epicboonfeat', 'exotic']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Boon of Misty Escape', 'General Feat', NULL, 'Epic Boon Feat (Prerequisite: Level 19+)
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Aberrant Dragonmark', 'General Feat', NULL, 'Dragonmark Feat (Prerequisite: Eberron Campaign, Can’t Have Another Dragonmark Feat)', '[{"name":"Aberrant Fortitude","description":"When you fail a Constitution saving throw, you can take a Reaction to roll 1d4 and add the number rolled to the save, potentially turning the failure into a success. Once you’ve used this benefit, you can’t use it again until you finish a Long Rest."},{"name":"Aberrant Magic","description":"You know one cantrip of your choice from the Sorcerer spell list. Also, choose a level 1 spell from that spell list. You always have that spell prepared. You can cast it once without a spell slot, and you regain the ability to cast it in that way when you finish a Short or Long Rest. You can also cast this spell using any spell slots you have. Constitution is your spellcasting ability for this spell."},{"name":"Aberrant Surge","description":"When you cast the level 1 spell from this feat, you can expend one of your Hit Point Dice and roll it. If you roll an even number, you gain a number of Temporary Hit Points equal to the number rolled. If you roll an odd number, one creature within 30 feet of you (not including you) takes Force damage equal to the number rolled. If no other creatures are in range, you take the damage."}]'::jsonb, FALSE, ARRAY['dragonmarkfeat', 'efota']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Mark of Detection', 'General Feat', NULL, 'Dragonmark Feat (Prerequisite: Eberron Campaign, Can’t have another Dragonmark Feat)
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Mark of Finding', 'General Feat', NULL, 'Dragonmark Feat (Prerequisite: Eberron Campaign, Can’t have another Dragonmark Feat)
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Mark of Handling', 'General Feat', NULL, 'Dragonmark Feat (Prerequisite: Eberron Campaign, Can’t have another Dragonmark Feat)', '[{"name":"Wild Intuition","description":"When you make an Intelligence (Nature) or Wisdom (Animal Handling) check, you can roll 1d4 and add the number rolled to the ability check."},{"name":"Primal Connection","description":"You always have the Animal Friendship and Speak with Animals spells prepared. You can cast each spell once without a spell slot, and you regain the ability to cast it in that way when you finish a Long Rest. You can also cast these spells using any spell slots you have. Intelligence, Wisdom, or Charisma is your spellcasting ability for these spells (choose when you select this feat)."},{"name":"Monstrous Connections","description":"When you reach character level 3, you can target a Monstrosity when you cast Animal Friendship or Speak with Animals if the creature’s Intelligence score is 3 or lower."},{"name":"Spells of the Mark","description":"If you have the Spellcasting or Pact Magic feature, the spells on the Mark of Handling Spells table are added to that feature’s spell list."},{"name":"Mark of Handling Spells","description":""}]'::jsonb, FALSE, ARRAY['dragonmarkfeat', 'efota']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Mark of Passage', 'General Feat', NULL, 'Dragonmark Feat (Prerequisite: Eberron Campaign, Can’t have another Dragonmark Feat)', '[{"name":"Courier’s Speed","description":"Your Speed increases by 5 feet."},{"name":"Intuitive Motion","description":"When you make a Strength (Athletics) or Dexterity (Acrobatics) check, you can roll 1d4 and add the number rolled to the ability check."},{"name":"Magical Passage","description":"You always have the Misty Step spell prepared. You can cast it once without a spell slot, and you regain the ability to cast it in that way when you finish a Long Rest. You can also cast it using any spell slots you have. Intelligence, Wisdom, or Charisma is your spellcasting ability for this spell (choose when you select this feat)."},{"name":"Spells of the Mark","description":"If you have the Spellcasting or Pact Magic feature, the spells on the Mark of Passage Spells table are added to that feature’s spell list."},{"name":"Mark of Passage Spells","description":""}]'::jsonb, FALSE, ARRAY['dragonmarkfeat', 'efota']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Mark of Making', 'General Feat', NULL, 'Dragonmark Feat (Prerequisite: Eberron Campaign, Can’t Have Another Dragonmark Feat)', '[{"name":"Artisan’s Intuition","description":"When you make an Intelligence (Arcana) check or an ability check using Artisan’s Tools, you can roll 1d4 and add the number rolled to the ability check."},{"name":"Spellsmith","description":"You know the Mending cantrip. You also always have the Magic Weapon spell prepared. You can cast it once without a spell slot, and you regain the ability to cast it in that way when you finish a Long Rest. You can also cast it using any spell slots you have. Intelligence, Wisdom, or Charisma is your spellcasting ability for these spells (choose when you select this feat)."},{"name":"Spells of the Mark","description":"If you have the Spellcasting or Pact Magic class feature, the spells on the Mark of Making Spells table are added to that feature’s spell list."}]'::jsonb, FALSE, ARRAY['dragonmarkfeat', 'efota']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Mark of Hospitality', 'General Feat', NULL, 'Dragonmark Feat (Prerequisite: Eberron Campaign, Can’t have another Dragonmark Feat)
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Mark of Healing', 'General Feat', NULL, 'Dragonmark Feat (Prerequisite: Eberron Campaign, Can’t have another Dragonmark Feat)
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Mark of Sentinel', 'General Feat', NULL, 'Dragonmark Feat (Prerequisite: Eberron Campaign, Can’t Have Another Dragonmark Feat)', '[{"name":"Sentinel’s Intuition","description":"When you make a Wisdom (Insight or Perception) check, you can roll 1d4 and add the number rolled to the ability check."},{"name":"Guardian’s Shield","description":"You always have the Shield spell prepared. You can cast it once without a spell slot, and you regain the ability to cast it in that way when you finish a Long Rest. You can also cast it using any spell slots you have. Intelligence, Wisdom, or Charisma is your spellcasting ability for this spell (choose when you select this feat)."},{"name":"Vigilant Guardian","description":"When a creature you can see within 5 feet of you is hit by an attack roll, you can take a Reaction to swap places with that creature, and you are hit by the attack instead. You can use this feature a number of times equal to your Proficiency Bonus and regain all expended uses when you finish a Long Rest."},{"name":"Spells of the Mark","description":"If you have the Spellcasting or Pact Magic class feature, the spells on the Mark of Sentinel Spells table are added to that feature’s spell list."},{"name":"Mark of Sentinel Spells","description":""}]'::jsonb, FALSE, ARRAY['dragonmarkfeat', 'efota']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Mark of Scribing', 'General Feat', NULL, 'Dragonmark Feat (Prerequisite: Eberron Campaign, Can’t Have Another Dragonmark Feat)
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Mark of Shadow', 'General Feat', NULL, 'Dragonmark Feat (Prerequisite: Eberron Campaign, Can’t Have Another Dragonmark Feat)', '[{"name":"Cunning Intuition","description":"When you make a Dexterity (Stealth) or Charisma (Performance) check, you can roll 1d4 and add the number rolled to the ability check."},{"name":"Shape Shadows","description":"You know the Minor Illusion cantrip. You also always have the Invisibility spell prepared. You can cast it once without a spell slot, and you regain the ability to cast it in that way when you finish a Long Rest. You can also cast it using any spell slots you have of the appropriate level. Intelligence, Wisdom, or Charisma is your spellcasting ability for these spells (choose when you select this feat)."},{"name":"Spells of the Mark","description":"If you have the Spellcasting or Pact Magic feature, the spells on the Mark of Shadow Spells table are added to that feature’s spell list."},{"name":"Mark of Shadow Spells","description":""}]'::jsonb, FALSE, ARRAY['dragonmarkfeat', 'efota']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Mark of Storm', 'General Feat', NULL, 'Dragonmark Feat (Prerequisite: Eberron Campaign, Can’t Have Another Dragonmark Feat)', '[{"name":"Windwright’s Intuition","description":"When you make a Dexterity (Acrobatics) check or an ability check using Navigator’s Tools, you can roll 1d4 and add the number rolled to the ability check."},{"name":"Storm’s Boon","description":"You have Resistance to Lightning damage."},{"name":"Storm Magic","description":"You know the Thunderclap cantrip. When you reach character level 3, you also always have the Gust of Wind spell prepared. You can cast it once without a spell slot, and you regain the ability to cast it in that way when you finish a Long Rest. You can also cast it using any spell slots you have of the appropriate level. Intelligence, Wisdom, or Charisma is your spellcasting ability for these spells (choose when you select this feat)."},{"name":"Spells of the Mark","description":"If you have the Spellcasting or Pact Magic feature, the spells on the Mark of Storm Spells table are added to that feature’s spell list."},{"name":"Mark of Storm Spells","description":""}]'::jsonb, FALSE, ARRAY['dragonmarkfeat', 'efota']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Mark of Warding', 'General Feat', NULL, 'Dragonmark Feat (Prerequisite: Eberron Campaign, Can’t Have Another Dragonmark Feat)
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Greater Aberrant Mark', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+, Aberrant Dragonmark Feat)
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Greater Mark of Finding', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+, Mark of Finding Feat)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 20."},{"name":"Improved Intuition","description":"When you use the Hunter’s Intuition benefit of your Mark of Finding feat, you can roll 1d6 instead of 1d4."},{"name":"Improved Finding","description":"When you use the Finder’s Magic benefit of your Mark of Finding to cast Hunter’s Mark without a spell slot, the range of the spell is doubled, and you can modify the spell so that the target can’t benefit from the Invisible condition for the duration."}]'::jsonb, FALSE, ARRAY['efota', 'greaterdragonmarkfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Greater Mark of Detection', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+, Mark of Detection Feat)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 20."},{"name":"Improved Intuition","description":"When you use the Deductive Intuition benefit of your Mark of Detection feat, you can roll 1d6 instead of 1d4."},{"name":"Shared Detection","description":"When you use the Magical Detection benefit of your Mark of Detection feat to cast See Invisibility without a spell slot, you can choose one creature you can see within 30 feet of yourself. That creature also gains the benefits of the spell for its duration."}]'::jsonb, FALSE, ARRAY['efota', 'greaterdragonmarkfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Greater Mark of Healing', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+, Mark of Healing Feat)
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Greater Mark of Handling', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+, Mark of Handling Feat)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 20."},{"name":"Improved Intuition","description":"When you use the Wild Intuition benefit of your Mark of Handling feat, you can roll 1d6 instead of 1d4."},{"name":"Improved Handling","description":"While you are mounted, immediately after you hit a target within 5 feet of your mount with a melee attack roll, your mount can take a Reaction to move up to its Speed or take the Attack action to make one attack only (your choice)."},{"name":"Subdue Animal","description":"As a Magic action, you exert command over one Beast or Monstrosity you can see within 30 feet of yourself. The target must succeed on a Wisdom saving throw (DC 8 plus your Wisdom modifier and Proficiency Bonus) or have the Frightened condition until the start of your next turn. You can use this benefit a number of times equal to your Proficiency Bonus, and you regain all expended uses when you finish a Long Rest."}]'::jsonb, FALSE, ARRAY['efota', 'greaterdragonmarkfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Greater Mark of Making', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+, Mark of Making Feat)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 20."},{"name":"Improved Intuition","description":"When you use the Artisan’s Intuition benefit of your Mark of Making feat, you can roll 1d6 instead of 1d4."},{"name":"Improved Making","description":"When you use the Spellsmith benefit of your Mark of Making feat to cast Magic Weapon without a spell slot, you cast the spell as its level 3 version."}]'::jsonb, FALSE, ARRAY['efota', 'greaterdragonmarkfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Greater Mark of Hospitality', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+, Mark of Hospitality Feat)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 20."},{"name":"Improved Intuition","description":"When you use the Ever Hospitable benefit of your Mark of Hospitality feat, you can roll 1d6 instead of 1d4."},{"name":"Inspired Hospitality","description":"When you cast Purify Food and Drink, you can modify the spell so that instead of its normal effect, each creature of your choice within 30 feet of you is refreshed. Each affected creature’s Exhaustion level is reduced by 1, and the creature gains Temporary Hit Points equal to your Proficiency Bonus plus your Intelligence, Wisdom, or Charisma modifier (choose when you select this feat). Once you modify the spell with this benefit, you can’t do so again until you finish a Long Rest."}]'::jsonb, FALSE, ARRAY['efota', 'greaterdragonmarkfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Greater Mark of Scribing', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+, Mark of Scribing Feat)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 20."},{"name":"Improved Intuition","description":"When you use the Gifted Scribe benefit of your Mark of Scribing feat, you can roll 1d6 instead of 1d4."},{"name":"Inspired Scribing","description":"When you cast Comprehend Languages, you can modify the spell to encompass up to three willing creatures you can see within 30 feet of yourself. Each chosen creature also gains the benefits of the spell for the duration. In addition, for the duration of the spell, you and the chosen creatures can communicate telepathically with each other while within 1 mile of each other. Once you modify the spell with this benefit, you can’t do so again until you finish a Long Rest."}]'::jsonb, FALSE, ARRAY['efota', 'greaterdragonmarkfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Greater Mark of Passage', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+, Mark of Passage Feat)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 20."},{"name":"Improved Intuition","description":"When you use the Intuitive Motion benefit of your Mark of Passage feat, you can roll 1d6 instead of 1d4."},{"name":"Inspired Passage","description":"When you use the Magical Passage benefit of your Mark of Passage feat to cast Misty Step without a spell slot, you can also choose up to two willing creatures you can see within 30 feet of yourself before you teleport. Each target can then take a Reaction to also teleport up to 30 feet to an unoccupied space it can see."}]'::jsonb, FALSE, ARRAY['efota', 'greaterdragonmarkfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Greater Mark of Sentinel', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+, Mark of Sentinel Feat)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 20."},{"name":"Improved Intuition","description":"When you use the Sentinel’s Intuition benefit of your Mark of Sentinel feat, you can roll 1d6 instead of 1d4."},{"name":"Improved Sentinel","description":"When you use the Vigilant Guardian benefit of your Mark of Sentinel feat, you can also make one attack with a weapon or an Unarmed Strike as part of that same Reaction."}]'::jsonb, FALSE, ARRAY['efota', 'greaterdragonmarkfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Greater Mark of Shadow', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+, Mark of Shadow Feat)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 20."},{"name":"Improved Intuition","description":"When you use the Cunning Intuition benefit of your Mark of Shadow feat, you can roll 1d6 instead of 1d4."},{"name":"Improved Shadow","description":"When you use the Shape Shadows benefit of your Mark of Shadow feat to cast Invisibility without a spell slot, you cast the spell as its level 3 version."}]'::jsonb, FALSE, ARRAY['efota', 'greaterdragonmarkfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Greater Mark of Storm', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+, Mark of Storm Feat)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 20."},{"name":"Improved Intuition","description":"When you use the Windwright’s Intuition benefit of your Mark of Storm feat, you can roll 1d6 instead of 1d4."},{"name":"Improved Storm","description":"When you use the Storm Magic benefit of your Mark of Storm feat to cast Gust of Wind without a spell slot, you also gain a Fly Speed of 60 feet for the duration of the spell."}]'::jsonb, FALSE, ARRAY['efota', 'greaterdragonmarkfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Potent Dragonmark', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+, Any Dragonmark Feat)', '[{"name":"Ability Score Increase","description":"Increase the spellcasting ability score used by your Dragonmark feat by 1, to a maximum of 20."},{"name":"Dragonmark Preparation","description":"You always have the spells on your Spells of the Mark list (if any) prepared."},{"name":"Dragonmark Spellcasting","description":"You have one extra spell slot to cast the spells granted by your Dragonmark feat. The spell slot’s level is half your level (round up), to a maximum of level 5. You regain the expended slot when you finish a Short or Long Rest. You can use this spell slot to cast only a spell you have prepared because of your Dragonmark feat or the Dragonmark Preparation benefit of this feat."}]'::jsonb, FALSE, ARRAY['efota', 'greaterdragonmarkfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Fey Pact', 'General Feat', NULL, 'Planar Pact Feat (Prerequisite: Can’t Have Another Planar Pact Feat)', '[{"name":"Fey Bond","description":"You know Sylvan. If you already know Sylvan when you select this feat, you instead learn one language of your choice from the language tables in the Player’s Handbook. You also gain Proficiency in the Nature skill."},{"name":"Fey Cantrips","description":"You know the Druidcraft cantrip and learn one other cantrip of your choice from the Divination or Enchantment school of magic. Intelligence, Wisdom, or Charisma is your spellcasting ability for these spells (choose when you select this feat)."},{"name":"Honeyed Words","description":". When you roll a 5 or lower on the d20 for a Charisma (Deception) or Charisma (Persuasion) check, you can take a Reaction to reroll the check, and you must use the new roll. Once you take this Reaction, you can’t use this benefit again until you finish a Long Rest."}]'::jsonb, FALSE, ARRAY['drops', 'drops0526', 'planarpactfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Greater Mark of Warding', 'General Feat', NULL, 'General Feat (Prerequisite: Level 4+, Mark of Warding Feat)', '[{"name":"Ability Score Increase","description":"Increase one ability score of your choice by 1, to a maximum of 20."},{"name":"Improved Intuition","description":"When you use the Warder’s Intuition benefit of your Mark of Warding feat, you can roll 1d6 instead of 1d4."},{"name":"Improved Warding","description":"When a creature makes an attack roll against you or a creature you can see within 30 feet of yourself, you can take a Reaction to impose Disadvantage on that roll. You can use this benefit a number of times equal to your Proficiency Bonus, and you regain all expended uses when you finish a Long Rest."}]'::jsonb, FALSE, ARRAY['efota', 'greaterdragonmarkfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
INSERT INTO official.feats (name, category, prerequisite, description, benefits, legacy, tags) VALUES ('Infernal Pact', 'General Feat', NULL, 'Planar Pact Feat (Prerequisite: Can’t Have Another Planar Pact Feat)', '[{"name":"Infernal Resistance","description":"You have Resistance to Fire damage and Poison damage."},{"name":"Infernal Sight","description":"You can see normally in Dim Light and Darkness - both magical and nonmagical - within 60 feet of yourself."},{"name":"Silver-Tongued","description":"You gain proficiency in the Deception skill."}]'::jsonb, FALSE, ARRAY['drops', 'drops0526', 'planarpactfeat']::TEXT[]) ON CONFLICT (name) DO UPDATE SET category = EXCLUDED.category, prerequisite = EXCLUDED.prerequisite, description = EXCLUDED.description, benefits = EXCLUDED.benefits, legacy = EXCLUDED.legacy, tags = EXCLUDED.tags;
